import{_ as a,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"183. Uniforms And Protective Clothing","description":"","frontmatter":{"title":"183. Uniforms And Protective Clothing","eba":"Mental Health Services 2024-2028","topics":["leave","personal-leave","long-service-leave","allowances"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/183-uniforms-and-protective-clothing.md","filePath":"ebas/mental-health/support-services/preliminary/183-uniforms-and-protective-clothing.md"}'),r={name:"ebas/mental-health/support-services/preliminary/183-uniforms-and-protective-clothing.md"};function l(i,e,s,h,p,c){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_183-uniforms-and-protective-clothing" tabindex="-1">183. Uniforms And Protective Clothing <a class="header-anchor" href="#_183-uniforms-and-protective-clothing" aria-label="Permalink to &quot;183. Uniforms And Protective Clothing&quot;">​</a></h1><p><strong>183.1</strong> Where an Employee is required to wear a uniform or any special clothing, the Employer will supply such uniform at no cost to the Employee and will replace it where necessary on a fair ‘wear and tear’ basis.</p><p><strong>183.2</strong> Employees shall be paid a uniform allowance in accordance with <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for purchasing uniform and special clothing, where they are not provided by the Employer under clause 183.1. The uniform allowance is payable for all absences on paid leave, other than absences on long service leave and sick leave beyond 21 days. Where, prior to the taking of leave, an Employee was paid a uniform allowance other than at the weekly rate, the rate payable is the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>183.3</strong> Uniforms and special clothing provided in accordance with clause 183.1 and clause 183.2 shall remain the property of the Employer.</p><p><strong>183.4</strong> Where Employees are responsible for laundering uniforms and special clothing, the Employer shall pay the laundry allowances set out in the rates table in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>. The Employee will be paid a laundry allowance per day or part thereof on duty, or an allowance per week, whichever is the lesser amount. The laundry allowance is not payable for absences of any kind.</p><p><strong>183.5</strong> The Employer shall provide such gloves, masks, protective clothing and safety appliances as are required for an Employee to properly and safely perform their job function. Where the Employee is required to purchase such clothing and equipment, they shall be reimbursed in full by the Employer.</p><p><strong>183.6</strong> The rounding provision does not apply to the calculation of this allowance.</p>',7)])])}const u=a(r,[["render",l]]);export{m as __pageData,u as default};
